input.command:
kubectl -n cockroachdb patch statefulset crdb-cluster --type='strategic' -p '{
  "spec": {
    "template": {
      "spec": {
        "containers": [{
          "name": "cockroachdb",
          "command": [
            "/bin/bash",
            "-ecx",
            "exec /cockroach/cockroach start --certs-dir=/cockroach/cockroach-certs --advertise-host=$(hostname -f) --http-addr=0.0.0.0:8080 --listen-addr=0.0.0.0:26257 --join=crdb-cluster-0.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.cockroachdb.svc.cluster.local:26257 --cache=.25 --max-sql-memory=.25"
          ],
          "env": [{"name": "COCKROACH_CHANNEL", "value": "kubernetes-secure"}],
          "livenessProbe": {
            "httpGet": {"path": "/health", "port": 8080, "scheme": "HTTPS"},
            "initialDelaySeconds": 30, "periodSeconds": 5, "timeoutSeconds": 1, "failureThreshold": 3
          },
          "readinessProbe": {
            "httpGet": {"path": "/health?ready=1", "port": 8080, "scheme": "HTTPS"},
            "initialDelaySeconds": 10, "periodSeconds": 5, "timeoutSeconds": 1, "failureThreshold": 2
          },
          "volumeMounts": [
            {"name": "datadir", "mountPath": "/cockroach/cockroach-data"},
            {"name": "certs", "mountPath": "/cockroach/cockroach-certs", "readOnly": true}
          ]
        }],
        "volumes": [{
          "name": "certs",
          "secret": {
            "secretName": "crdb-certs",
            "defaultMode": 256
          }
        }]
      }
    }
  }
}' 2>&1
